	// StoreTypeValkey is the Valkey store type
	StoreTypeValkey = "valkey"
)

var (
	storeInstance Store
	once          sync.Once
)

// Storage returns the singleton store instance
func Storage() Store {
	once.Do(func() {
		var err error
		storeInstance, err = initStore()
		if err != nil {
			klog.Fatalf("Failed to initialize store: %v", err)
		}
	})
	return storeInstance
}

