		return nil, fmt.Errorf("VALKEY_PASSWORD is required (set VALKEY_PASSWORD_REQUIRED=false to disable)")
	}

	// Parse comma-separated addresses
	addresses := strings.Split(addr, ",")
	for i := range addresses {
		addresses[i] = strings.TrimSpace(addresses[i])
	}

	disableCache := false
	if val := os.Getenv("VALKEY_DISABLE_CACHE"); val != "" {
		disableCache = strings.ToLower(val) == "true"
	}

	forceSingle := false
	if val := os.Getenv("VALKEY_FORCE_SINGLE"); val != "" {
		forceSingle = strings.ToLower(val) == "true"
	}

	client, err := valkey.NewClient(valkey.ClientOption{
		InitAddress:  addresses,
		Password:     password,
		DisableCache: disableCache,
		ForceSingleClient: forceSingle,
	})
	if err != nil {
		return nil, err
	}

	return &ValkeyStore{client: client}, nil
}

