		Addr:     addr,
		Password: password,
		DB:       0,
	})

	return &RedisStore{client: client}, nil
}

// Ping checks if Redis is reachable
func (s *RedisStore) Ping(ctx context.Context) error {
	pong, err := s.client.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if pong != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", pong)
	}
	return nil
}

// GetSandboxBySessionID retrieves a sandbox by session ID
func (s *RedisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := KeyPrefix + sessionID
	data, err := s.client.Get(ctx, key).Bytes()
	if err != nil {
		if err == redis.Nil {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, err
	}
	return &sandbox, nil
}

// StoreSandbox stores a new sandbox atomically
func (s *RedisStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return fmt.Errorf("expiresAt cannot be zero")
	}

	key := KeyPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	pipe := s.client.Pipeline()

	// Store the sandbox data with SETNX (only if not exists)
	setCmd := pipe.SetNX(ctx, key, data, time.Until(sandbox.ExpiresAt)+time.Hour)

	// Add to expiry index
	expiryCmd := pipe.ZAdd(ctx, ExpiryIndex, redis.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	})

	// Add to last activity index
	activityCmd := pipe.ZAdd(ctx, LastActivityIndex, redis.Z{
		Score:  float64(time.Now().Unix()),
		Member: sandbox.SessionID,
	})

	_, err = pipe.Exec(ctx)
	if err != nil {
		return err
	}

	// Check if SETNX succeeded
	if !setCmd.Val() {
		return fmt.Errorf("session already exists")
	}

	// Verify ZADD commands succeeded
	if err := expiryCmd.Err(); err != nil {
		return err
	}
	if err := activityCmd.Err(); err != nil {
		return err
	}

	return nil
}

// UpdateSandbox updates an existing sandbox
func (s *RedisStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}

	key := KeyPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	// Use SET with XX (only if exists)
	setCmd := s.client.SetXX(ctx, key, data, 0)
	success, err := setCmd.Result()
	if err != nil {
		return err
	}
	if !success {
		return ErrNotFound
	}

	return nil
}

// DeleteSandboxBySessionID deletes a sandbox by session ID
func (s *RedisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := KeyPrefix + sessionID

	pipe := s.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, ExpiryIndex, sessionID)
	pipe.ZRem(ctx, LastActivityIndex, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

// ListExpiredSandboxes lists sandboxes that expired before the given time
func (s *RedisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return []*types.SandboxInfo{}, nil
	}

	sessionIDs, err := s.client.ZRangeByScore(ctx, ExpiryIndex, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   strconv.FormatInt(before.Unix(), 10),
		Count: int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

// ListInactiveSandboxes lists sandboxes that were inactive before the given time
func (s *RedisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return []*types.SandboxInfo{}, nil
	}

	sessionIDs, err := s.client.ZRangeByScore(ctx, LastActivityIndex, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   strconv.FormatInt(before.Unix(), 10),
		Count: int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

// loadSandboxesBySessionIDs loads sandboxes by their session IDs
func (s *RedisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = KeyPrefix + id
	}

	pipe := s.client.Pipeline()
	cmds := make([]*redis.StringCmd, len(keys))
	for i, key := range keys {
		cmds[i] = pipe.Get(ctx, key)
	}
	_, err := pipe.Exec(ctx)
	if err != nil && err != redis.Nil {
		return nil, err
	}

	var sandboxes []*types.SandboxInfo
	for _, cmd := range cmds {
		data, err := cmd.Bytes()
		if err == redis.Nil {
			// Skip missing keys (orphan ZSET members)
			continue
		}
		if err != nil {
			return nil, err
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal(data, &sandbox); err != nil {
			continue
		}
		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

// UpdateSessionLastActivity updates the last activity time for a session
func (s *RedisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return fmt.Errorf("sessionID cannot be empty")
	}

	// Verify session exists
	key := KeyPrefix + sessionID
	exists, err := s.client.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	if at.IsZero() {
		at = time.Now()
	}

	return s.client.ZAdd(ctx, LastActivityIndex, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Err()
}

// Close closes the Redis connection
func (s *RedisStore) Close() error {
	return s.client.Close()
}

