package workloadmanager

import (
	"fmt"
	"os"
	"strconv"
	"time"
)

// Config holds the workload manager configuration
type Config struct {
	// Port is the HTTP port to listen on
	Port int

	// EnableTLS enables TLS
	EnableTLS bool

	// TLSCertPath is the path to the TLS certificate
	TLSCertPath string

	// TLSKeyPath is the path to the TLS key
	TLSKeyPath string

	// EnableAuth enables authentication
	EnableAuth bool

	// InCluster indicates if running in cluster
	InCluster bool

	// Kubeconfig is the path to kubeconfig
	Kubeconfig string

	// ReadTimeout is the HTTP read timeout
	ReadTimeout time.Duration

	// IdleTimeout is the HTTP idle timeout
	IdleTimeout time.Duration

	// SandboxTTL is the default sandbox TTL
	SandboxTTL time.Duration

	// IdleTimeout is the sandbox idle timeout
	IdleTimeoutDuration time.Duration
}

// NewConfig creates a new Config from environment and defaults
func NewConfig() *Config {
	port := 8080
	if p := os.Getenv("PORT"); p != "" {
		if parsed, err := strconv.Atoi(p); err == nil {
			port = parsed
		}
	}

	enableTLS := false
	if v := os.Getenv("ENABLE_TLS"); v != "" {
		enableTLS = v == "true" || v == "1"
	}

	enableAuth := false
	if v := os.Getenv("ENABLE_AUTH"); v != "" {
		enableAuth = v == "true" || v == "1"
	}

	inCluster := true
	if v := os.Getenv("IN_CLUSTER"); v != "" {
		inCluster = v == "true" || v == "1"
	}

	return &Config{
		Port:                port,
		EnableTLS:           enableTLS,
		TLSCertPath:         os.Getenv("TLS_CERT_PATH"),
		TLSKeyPath:          os.Getenv("TLS_KEY_PATH"),
		EnableAuth:          enableAuth,
		InCluster:           inCluster,
		Kubeconfig:          os.Getenv("KUBECONFIG"),
		ReadTimeout:         HTTPReadTimeout,
		IdleTimeout:         HTTPIdleTimeout,
		SandboxTTL:          DefaultSandboxTTL,
		IdleTimeoutDuration: DefaultSandboxIdleTimeout,
	}
}

// Validate validates the configuration
func (c *Config) Validate() error {
	if c.Port < 1 || c.Port > 65535 {
		return fmt.Errorf("invalid port: %d", c.Port)
	}

	if c.EnableTLS {
		if c.TLSCertPath == "" {
			return fmt.Errorf("TLS_CERT_PATH is required when TLS is enabled")
		}
		if c.TLSKeyPath == "" {
			return fmt.Errorf("TLS_KEY_PATH is required when TLS is enabled")
		}
	}

	return nil
}

