package workloadmanager

import (
	"time"
)

// Constants for workload manager
const (
	// DefaultSandboxTTL is the default TTL for sandboxes
	DefaultSandboxTTL = 8 * time.Hour

	// DefaultSandboxIdleTimeout is the default idle timeout before GC
	DefaultSandboxIdleTimeout = 15 * time.Minute

	// DefaultSessionTimeout is the default session timeout
	DefaultSessionTimeout = 15 * time.Minute

	// TokenCacheCapacity is the LRU cache capacity for token validation
	TokenCacheCapacity = 1000

	// TokenCacheTTL is the TTL for cached token validations
	TokenCacheTTL = 5 * time.Minute

	// SandboxCreationTimeout is the timeout for sandbox creation
	SandboxCreationTimeout = 2 * time.Minute

	// SandboxDeleteTimeout is the timeout for sandbox deletion
	SandboxDeleteTimeout = 30 * time.Second

	// GCTickInterval is the interval between GC runs
	GCTickInterval = 15 * time.Second

	// HTTPReadTimeout is the HTTP read timeout
	HTTPReadTimeout = 15 * time.Second

	// HTTPIdleTimeout is the HTTP idle timeout
	HTTPIdleTimeout = 90 * time.Second

	// HTTPShutdownTimeout is the HTTP shutdown timeout
	HTTPShutdownTimeout = 15 * time.Second
)

// Label and annotation keys
const (
	// LastActivityAnnotationKey is the annotation key for last activity time
	LastActivityAnnotationKey = "last-activity-time"

	// SandboxNameLabelKey is the label key for sandbox name
	SandboxNameLabelKey = "runtime.agentcube.io/sandbox-name"

	// SessionIDLabelKey is the label key for session ID
	SessionIDLabelKey = "runtime.agentcube.io/session-id"

	// PodNameAnnotationKey is the annotation key for sandbox pod name
	PodNameAnnotationKey = "agents.x-k8s.io/sandbox-pod-name"
)
